const incoming = ($json && typeof $json === 'object') ? $json : {};
const root = incoming.body && typeof incoming.body === 'object' && Object.keys(incoming.body).length
  ? incoming.body
  : incoming;

const CR = String.fromCharCode(13);

function pickFirst(...vals) {
  for (const v of vals) {
    if (v === undefined || v === null) continue;
    const str = typeof v === 'string' ? v.trim() : v;
    if (typeof str === 'string' && str.length === 0) continue;
    return str;
  }
  return undefined;
}

function toCleanString(value) {
  if (value === undefined || value === null) return '';
  if (typeof value === 'string') {
    const normalized = value.split(CR).join(' ');
    return normalized.replace(/\s+/g, ' ').trim();
  }
  return String(value);
}

function safeParseObject(value) {
  if (value === undefined || value === null) return null;
  if (typeof value === 'object' && !Array.isArray(value)) return value;
  if (typeof value === 'string') {
    const trimmed = value.trim();
    if (!trimmed) return null;
    try {
      const parsed = JSON.parse(trimmed);
      if (parsed && typeof parsed === 'object' && !Array.isArray(parsed)) return parsed;
    } catch {}
  }
  return null;
}

function clampWordCount(value, fallback = 600) {
  if (!Number.isFinite(value)) return fallback;
  return Math.max(120, Math.min(1600, Math.round(value)));
}

// 解析语言偏好：支持 language 或 output_language 字段
const rawLang = pickFirst(root.language, root.output_language, '简体中文');
const outputLanguage = (rawLang.includes('繁') || rawLang.toLowerCase().includes('traditional') || rawLang.toLowerCase().includes('tw') || rawLang.toLowerCase().includes('hk')) 
  ? '繁体中文' 
  : '简体中文';

const workflowId = pickFirst(root.workflow_id, root.workflowId, 'flow_creative_script');
const workflowName = pickFirst(root.workflow_name, root.workflowName, '首页智能创作');
const taskId = pickFirst(root.task_id, root.taskId, root.replication_id, root.replicationId);
if (!taskId) throw new Error('task_id is required');

const userId = pickFirst(root.user_id, root.userId);
if (!userId) throw new Error('user_id is required');

const ideaText = toCleanString(pickFirst(root.idea_text, root.ideaText, root.text, root.content, root.topic, root.prompt));
if (!ideaText) throw new Error('idea_text is required');

return [{
  json: {
    task_id: taskId,
    replication_id: pickFirst(root.replication_id, root.replicationId, taskId),
    user_id: userId,
    idea_text: ideaText,
    output_language: outputLanguage, // 关键：传给 AI 的指令
    target_word_count: clampWordCount(Number(pickFirst(root.word_count, root.wordCount, 600))),
    workflow_id: workflowId,
    workflow_name: workflowName,
    api_key: pickFirst(root.api_key, root.apiKey, ''),
    callback_url: pickFirst(root.callback_url, root.callbackUrl, ''),
    app_url: pickFirst(root.app_url, root.appUrl, ''),
    style_rules: safeParseObject(root.style_rules ?? root.styleRules ?? null),
    source: pickFirst(root.source, 'creative_workspace'),
    raw_body: root
  }
}];

