/**
 * 核心逻辑：从杂乱的字符串中提取第一个合法的 JSON 对象
 * 采用括号平衡计数法，能够有效处理重复生成的 JSON 或包含 Markdown 标签的情况
 */
function robustExtractJson(str) {
  if (typeof str !== 'string') return null;

  // 1. 预处理：去除可能的 Unicode 零宽字符或干扰项
  const cleanStr = str.replace(/[\u200B-\u200D\uFEFF]/g, '').trim();

  let firstOpenBracket = cleanStr.indexOf('{');
  if (firstOpenBracket === -1) return null;

  let stack = 0;
  let jsonCandidate = "";
  let found = false;

  // 2. 括号平衡查找
  for (let i = firstOpenBracket; i < cleanStr.length; i++) {
    const char = cleanStr[i];
    if (char === '{') stack++;
    if (char === '}') stack--;

    if (stack === 0 && i > firstOpenBracket) {
      jsonCandidate = cleanStr.slice(firstOpenBracket, i + 1);
      found = true;
      break;
    }
  }

  if (!found) return null;

  // 3. 尝试解析
  try {
    return JSON.parse(jsonCandidate);
  } catch (e) {
    // 4. 容错处理：如果解析失败，尝试清洗掉内部可能存在的 Markdown 干扰
    try {
      const secondaryClean = jsonCandidate
        .replace(/\\n/g, '\n') // 处理转义换行
        .replace(/```json/g, '')
        .replace(/```/g, '');
      return JSON.parse(secondaryClean);
    } catch (e2) {
      console.error("JSON Parsing failed after cleaning:", e2);
      return null;
    }
  }
}

// 获取 n8n 输入
const item = $input.first();
const rawOutput = item.json?.output ?? '';

// 执行提取
const parsed = robustExtractJson(rawOutput);

// 如果解析依然失败，抛出详细错误
if (!parsed) {
  throw new Error('解析失败：输入内容不包含合法的 JSON 结构。请检查大模型输出格式。');
}

// 返回处理后的数据结构
return [
  {
    json: {
      ...item.json, // 保留原始数据
      parsed_output: parsed, // 存储解析后的完整对象
      // 展开常用字段，并提供防御性空值
      angle: parsed.angle || '',
      hook_options: Array.isArray(parsed.hook_options) ? parsed.hook_options : [],
      outline: Array.isArray(parsed.outline) ? parsed.outline : [],
      claims_to_verify: Array.isArray(parsed.claims_to_verify) ? parsed.claims_to_verify : [],
      search_keywords: Array.isArray(parsed.search_keywords) ? parsed.search_keywords : [],
      style_constraints: Array.isArray(parsed.style_constraints) ? parsed.style_constraints : [],
      cta_templates: Array.isArray(parsed.cta_templates) ? parsed.cta_templates : [],
    }
  }
];

