function stripFence(s) {
  s = String(s ?? '').trim();
  // 使用 \`{3} 替代连续的反引号，防止代码在编辑器中被截断
  return s
    .replace(/^\`{3}(?:json|JSON)?\s*/i, '')
    .replace(/\s*\`{3}$/, '')
    .trim();
}

function extractJsonObjectString(s) {
  s = String(s ?? '');
  const first = s.indexOf('{');
  const last = s.lastIndexOf('}');
  if (first === -1 || last === -1 || last <= first) return '';
  return s.slice(first, last + 1);
}

function safeParse(s) {
  try {
    return JSON.parse(s);
  } catch (e) {
    return null;
  }
}

function normalizeTags(v) {
  if (Array.isArray(v)) {
    return v.map(x => String(x || '').trim()).filter(Boolean);
  }
  if (typeof v === 'string') {
    return v
      .split(/[\n,，\s]+/)
      .map(x => x.trim())
      .filter(Boolean)
      .map(x => x.startsWith('#') ? x : `#${x}`);
  }
  return [];
}

// 1. 获取输入数据
const inputData = $input.first();
const rawOutputText = String(inputData.json?.output ?? '').trim();

// 2. 提取并解析 JSON
const cleanedText = extractJsonObjectString(stripFence(rawOutputText));
const parsedResult = safeParse(cleanedText);

if (!parsedResult) {
  throw new Error('解析失败：AI 输出的内容不是有效的 JSON。原始输出：' + rawOutputText.slice(0, 100));
}

// 3. 提取字段（兼容简繁体 Key 名）
const finalTitle = parsedResult['标题'] || parsedResult['標題'] || parsedResult.title || '';
const finalContent = parsedResult['正文'] || parsedResult['正文'] || parsedResult.script_content || parsedResult.content || '';
const finalHashtags = normalizeTags(parsedResult['标签'] ?? parsedResult['標籤'] ?? parsedResult.hashtags ?? []);

// 4. 返回结果
return [
  {
    json: {
      ...inputData.json,
      parsed_output: parsedResult,

      // 统一标准英文字段输出
      title: finalTitle,
      script_content: finalContent,
      hashtags: finalHashtags,

      // 保持中文 Key 的兼容性
      标题: finalTitle,
      正文: finalContent,
      标签: finalHashtags
    }
  }
];

const input = $('标准化输入').item.json || {};
const current = $json || {};

function ensureArray(value) {
  if (Array.isArray(value)) return value;
  if (value === undefined || value === null || value === '') return [];
  return [value];
}

function asText(value) {
  if (value === undefined || value === null) return '';
  if (typeof value === 'string') return value.trim();
  return String(value).trim();
}

function pickFirst(...values) {
  for (const v of values) {
    if (v === undefined || v === null) continue;
    if (typeof v === 'string' && v.trim() === '') continue;
    return v;
  }
  return undefined;
}

function summarizeList(label, items, formatter) {
  const arr = ensureArray(items)
    .map((item, index) => {
      try {
        return formatter(item, index);
      } catch {
        return '';
      }
    })
    .map(v => asText(v))
    .filter(Boolean);

  if (!arr.length) return '';
  return `${label}:\n- ${arr.join('\n- ')}`;
}

function normalizeStyleContext(rawStyleRules) {
  const rules = rawStyleRules && typeof rawStyleRules === 'object' ? rawStyleRules : {};

  const evidence = rules.evidence && typeof rules.evidence === 'object' ? rules.evidence : {};
  const tone = rules.tone && typeof rules.tone === 'object' ? rules.tone : {};
  const structure = rules.structure && typeof rules.structure === 'object' ? rules.structure : {};
  const language = rules.language && typeof rules.language === 'object' ? rules.language : {};
  const taboo = rules.taboo && typeof rules.taboo === 'object' ? rules.taboo : {};
  const persona = rules.persona && typeof rules.persona === 'object' ? rules.persona : {};
  const rhythm = rules.rhythm && typeof rules.rhythm === 'object' ? rules.rhythm : {};

  const representativeSnippets = ensureArray(
    evidence.representative_snippets || evidence.representativeSnippets
  );
  const openingPatterns = ensureArray(
    structure.opening_patterns || structure.openingPatterns
  );
  const paragraphPatterns = ensureArray(
    structure.paragraph_patterns || structure.paragraphPatterns
  );
  const ctaPatterns = ensureArray(
    structure.cta_patterns || structure.ctaPatterns
  );
  const keywords = ensureArray(language.keywords);
  const avoided = ensureArray(taboo.avoid || taboo.forbidden || taboo.words);
  const pacingMarkers = ensureArray(
    rhythm.pacing_markers || rhythm.pacingMarkers
  );

  return {
    source: 'derived_from_style_rules',
    docCount: Number(
      pickFirst(
        rules.sample_count,
        rules.sampleCount,
        evidence.sample_count,
        evidence.sampleCount,
        0
      )
    ) || 0,
    caseCount: representativeSnippets.length,
    isInsufficient: representativeSnippets.length === 0,
    fetchError: null,

    styleSummaries: [
      {
        docTitle: 'style_rules',
        domain: asText(persona.domain || persona.field || persona.track),
        tone: [
          asText(tone.main),
          asText(tone.voice),
          asText(tone.style)
        ].filter(Boolean).join(' / '),
        keyMoves: [
          asText(structure.core_logic || structure.coreLogic),
          asText(language.expression_preference || language.expressionPreference),
          asText(rhythm.pace || rhythm.speed)
        ].filter(Boolean).join('｜')
      }
    ].filter(item => item.domain || item.tone || item.keyMoves),

    writingBlocks: [
      ...openingPatterns.map(v => ({ label: '开头', pattern: asText(v) })),
      ...paragraphPatterns.map(v => ({ label: '段落推进', pattern: asText(v) })),
      ...ctaPatterns.map(v => ({ label: '结尾CTA', pattern: asText(v) }))
    ].filter(item => item.pattern),

    rawTextExcerpts: representativeSnippets.map(item => ({
      docTitle: asText(item.docTitle || item.title || '样例片段'),
      text: asText(item.snippet || item.text),
      note: asText(item.note)
    })).filter(item => item.text),

    extracted: {
      keywords,
      avoided,
      pacingMarkers,
      tone,
      structure,
      language,
      taboo,
      persona,
      rhythm,
      evidence
    }
  };
}

const explicitStyleContext =
  input.style_context ||
  input.styleContext ||
  null;

const style =
  explicitStyleContext && typeof explicitStyleContext === 'object'
    ? explicitStyleContext
    : normalizeStyleContext(input.style_rules);

const summaryParts = [];

summaryParts.push(`样本文档：${style.docCount || 0} 篇`);
summaryParts.push(`案例片段：${style.caseCount || 0} 条`);

if (style.source) {
  summaryParts.push(`来源：${style.source}`);
}

const toneSummary = summarizeList(
  '风格提炼',
  style.styleSummaries,
  (item) => {
    const bits = [
      asText(item.docTitle),
      asText(item.domain) ? `领域：${asText(item.domain)}` : '',
      asText(item.tone) ? `口吻：${asText(item.tone)}` : '',
      asText(item.keyMoves) ? `招式：${asText(item.keyMoves)}` : ''
    ].filter(Boolean);
    return bits.join('｜');
  }
);
if (toneSummary) summaryParts.push(toneSummary);

const blockSummary = summarizeList(
  '结构模板',
  style.writingBlocks,
  (item) => {
    const left = asText(item.label || item.purpose || '模块');
    const right = asText(item.pattern || item.template || item.text);
    return right ? `${left} → ${right}` : '';
  }
);
if (blockSummary) summaryParts.push(blockSummary);

const excerptSummary = summarizeList(
  '样例片段',
  style.rawTextExcerpts,
  (item) => {
    const title = asText(item.docTitle || '样例');
    const note = asText(item.note);
    const text = asText(item.text);
    return [title, note ? `说明：${note}` : '', text].filter(Boolean).join('｜');
  }
);
if (excerptSummary) summaryParts.push(excerptSummary);

if (style.isInsufficient) {
  summaryParts.push('⚠️ 历史样本不足，当前仅基于 style_rules 做风格推断。');
}

const styleSummaryText = summaryParts.filter(Boolean).join('\n\n');

const planPayload = {
  idea: pickFirst(input.idea_text, input.idea, ''),
  target_word_count: Number(
    pickFirst(input.target_word_count, input.word_count, input.wordCount, 600)
  ) || 600,
  style_rules: input.style_rules ?? null,
  style_context: style,
  warnings: {
    insufficient_history: Boolean(style.isInsufficient),
    fetch_error: style.fetchError || null
  }
};

return [
  {
    json: {
      ...input,
      balance_check: current,
      plan_payload: planPayload,
      style_summary_text: styleSummaryText,
      style_context: style,
      history_warning: Boolean(style.isInsufficient)
    }
  }
];

